/**
 * Segment Tree implementation for Range Maximum Query (RMQ)
 * Stores maximum values over a fixed range of indices [1, V_SIZE].
 */
class SegmentTree {
    constructor(vSize) {
        // V_SIZE is the maximum value + 1, so indices 1 to V_SIZE-1 are valid values.
        this.V_SIZE = vSize;
        // Tree size: 4 * V_SIZE is a safe upper bound for array based implementation
        this.tree = new Array(4 * vSize).fill(0);
    }

    // Internal recursive update function
    _update(node, start, end, idx, val) {
        if (start === end) {
            // Update the leaf node by taking the maximum
            this.tree[node] = Math.max(this.tree[node], val);
            return;
        }

        const mid = Math.floor((start + end) / 2);
        if (idx <= mid) {
            this._update(2 * node, start, mid, idx, val);
        } else {
            this._update(2 * node + 1, mid + 1, end, idx, val);
        }

        // Update internal node: maximum of children
        this.tree[node] = Math.max(this.tree[2 * node], this.tree[2 * node + 1]);
    }

    // Public update: point update at index 'idx' with value 'val'
    update(idx, val) {
        if (idx < 1 || idx >= this.V_SIZE) return;
        this._update(1, 1, this.V_SIZE - 1, idx, val);
    }

    // Internal recursive query function
    _query(node, start, end, l, r) {
        // No overlap
        if (r < start || end < l) {
            return 0; // Identity element for max operation
        }

        // Complete overlap
        if (l <= start && end <= r) {
            return this.tree[node];
        }

        // Partial overlap
        const mid = Math.floor((start + end) / 2);
        const p1 = this._query(2 * node, start, mid, l, r);
        const p2 = this._query(2 * node + 1, mid + 1, end, l, r);
        return Math.max(p1, p2);
    }

    // Public query: returns max value in range [l, r]
    query(l, r) {
        if (l > r || l < 1 || r >= this.V_SIZE) return 0;
        return this._query(1, 1, this.V_SIZE - 1, l, r);
    }
}


function solve(nums, k) {
    const N = nums.length;
    if (N === 0) return 0;

    // Maximum value is 10^5. We use V_SIZE = 100001 for 1-based indexing up to 100000.
    const V_SIZE = 100001; 

    // DP_up[i]: Max score ending at i, where transition j->i was increasing (nums[j] < nums[i])
    const DP_up = new Array(N).fill(0);
    // DP_down[i]: Max score ending at i, where transition j->i was decreasing (nums[j] > nums[i])
    const DP_down = new Array(N).fill(0);

    // ST_down: Stores max(DP_down[j]) indexed by nums[j]. Used to calculate DP_up[i].
    // We query prefix max (value < nums[i]).
    const ST_down = new SegmentTree(V_SIZE);

    // ST_up: Stores max(DP_up[j]) indexed by nums[j]. Used to calculate DP_down[i].
    // We query suffix max (value > nums[i]).
    const ST_up = new SegmentTree(V_SIZE);

    let maxScore = 0;

    for (let i = 0; i < N; i++) {
        const val_i = nums[i];

        // Step 1: Calculate DP_up[i] and DP_down[i] using predecessors available in STs.

        // DP_up[i]: Predecessor j must have resulted in DP_down[j], and nums[j] < nums[i].
        // Query range [1, val_i - 1] in ST_down.
        const max_pred_down = ST_down.query(1, val_i - 1);
        // Base score for length 1 is val_i + 0.
        DP_up[i] = val_i + max_pred_down;

        // DP_down[i]: Predecessor j must have resulted in DP_up[j], and nums[j] > nums[i].
        // Query range [val_i + 1, V_SIZE - 1] in ST_up.
        const max_pred_up = ST_up.query(val_i + 1, V_SIZE - 1);
        // Base score for length 1 is val_i + 0.
        DP_down[i] = val_i + max_pred_up;


        // Step 2: Update overall maximum score
        maxScore = Math.max(maxScore, DP_up[i], DP_down[i]);

        // Step 3: Make results from index j = i - k available for future calculations
        // These results are now ready to be inserted into the Segment Trees.
        const j = i - k;
        if (j >= 0) {
            // Insert DP_down[j] into ST_down at index nums[j]
            ST_down.update(nums[j], DP_down[j]);
            // Insert DP_up[j] into ST_up at index nums[j]
            ST_up.update(nums[j], DP_up[j]);
        }
    }

    return maxScore;
}

