 * Segment Tree implementation for Range Maximum Query (RMQ)
 * Stores maximum values over a fixed range of indices [1, V_SIZE].
 */
class SegmentTree {
    constructor(vSize) {
        // V_SIZE is the maximum value + 1, so indices 1 to V_SIZE-1 are valid values.
        this.V_SIZE = vSize;
        // Tree size: 4 * V_SIZE is a safe upper bound for array based implementation
        this.tree = new Array(4 * vSize).fill(0);
    }

    // Internal recursive update function
    _update(node, start, end, idx, val) {
        if (start === end) {
            // Update the leaf node by taking the maximum
            this.tree[node] = Math.max(this.tree[node], val);
            return;
        }

        const mid = Math.floor((start + end) / 2);
        if (idx <= mid) {
            this._update(2 * node, start, mid, idx, val);
        } else {
            this._update(2 * node + 1, mid + 1, end, idx, val);
        }

        // Update internal node: maximum of children
        this.tree[node] = Math.max(this.tree[2 * node], this.tree[2 * node + 1]);
    }

    // Public update: point update at index 'idx' with value 'val'
    update(idx, val) {
        if (idx < 1 || idx >= this.V_SIZE) return;
        this._update(1, 1, this.V_SIZE - 1, idx, val);
    }

    // Internal recursive query function
    _query(node, start, end, l, r) {
        // No overlap
        if (r < start || end < l) {
            return 0; // Identity element for max operation
        }

        // Complete overlap
        if (l <= start && end <= r) {
            return this.tree[node];
        }

        // Partial overlap
        const mid = Math.floor((start + end) / 2);
        const p1 = this._query(2 * node, start, mid, l, r);
        const p2 = this._query(2 * node + 1, mid + 1, end, l, r);
        return Math.max(p1, p2);
    }

    // Public query: returns max value in range [l, r]
    query(l, r) {
        if (l > r || l < 1 || r >= this.V_SIZE) return 0;
        return this._query(1, 1, this.V_SIZE - 1, l, r);
    }
}


